import{_ as o,o as a,c as r,a3 as e}from"./chunks/framework.DACwFHq9.js";const c=JSON.parse('{"title":"系统脉搏","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/system-pulse.md","filePath":"user-guide/tools/system-pulse.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/system-pulse.md"};function n(s,t,i,d,h,u){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="系统脉搏" tabindex="-1">系统脉搏 <a class="header-anchor" href="#系统脉搏" aria-label="Permalink to &quot;系统脉搏&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>系统脉搏是一个<strong>实时硬件监控仪表盘</strong>，让你像看心电图一样随时掌握电脑的运行状态。它覆盖 CPU、内存、磁盘、网络和 GPU 五个维度的关键指标，并配有历史趋势折线图，帮助你快速发现性能瓶颈和异常。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>五大维度实时监控</strong>：CPU（含多核热力图）、内存（含 Swap）、磁盘（容量 + I/O 速率）、网络（上/下行）、GPU（含 NVIDIA 编解码）</li><li><strong>历史趋势折线图</strong>：每个维度都配有 60 秒滚动趋势图，变化一目了然</li><li><strong>GPU 深度分析</strong>：支持 NVIDIA 显卡的编解码器使用率监控，适合视频创作者和 AI 开发者</li><li><strong>三种 UI 密度</strong>：紧凑 / 标准 / 宽大三档布局，适应不同屏幕尺寸和信息密度偏好</li><li><strong>状态快照导出</strong>：一键复制当前状态为文本，或导出完整历史记录为 JSON 文件</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="三步开始监控" tabindex="-1">三步开始监控 <a class="header-anchor" href="#三步开始监控" aria-label="Permalink to &quot;三步开始监控&quot;">​</a></h3><p><strong>第一步：打开工具</strong></p><p>在左侧工具列表中找到 <strong>系统脉搏</strong>，点击进入。你会看到页面显示&quot;监控已暂停&quot;的空状态，中间有一个 <strong>立即开启</strong> 按钮。</p><blockquote><p>TODO: 截图 - 初始空状态界面，标注&quot;立即开启&quot;按钮</p></blockquote><p><strong>第二步：启动监控</strong></p><p>点击 <strong>立即开启</strong> 按钮，或点击右上角的开关切换到开启状态。页面会短暂显示&quot;正在采集系统数据…&quot;的加载动画，随后自动展示完整的监控仪表盘。</p><blockquote><p>TODO: 截图 - 加载中的状态</p></blockquote><p><strong>第三步：观察仪表盘</strong></p><p>开启后页面从上到下分为以下几个区域：</p><ol><li><strong>顶部状态栏</strong> — 一行摘要展示 CPU、内存、网络速率和 GPU 使用率，右侧显示当前时间</li><li><strong>监控卡片网格</strong> — 每个维度一张毛玻璃卡片，包含核心数值、历史折线图和详细指标</li></ol><blockquote><p>TODO: 截图 - 完整的监控仪表盘，标注状态栏和各卡片区域</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="状态栏-顶部摘要条" tabindex="-1">状态栏（顶部摘要条） <a class="header-anchor" href="#状态栏-顶部摘要条" aria-label="Permalink to &quot;状态栏（顶部摘要条）&quot;">​</a></h3><p>位于页面最上方，用紧凑的一行展示所有关键维度的实时概览：</p><table tabindex="0"><thead><tr><th>指标</th><th>颜色标识</th><th>说明</th></tr></thead><tbody><tr><td>CPU</td><td>按使用率变色</td><td>全局 CPU 使用率百分比</td></tr><tr><td>内存</td><td>正常</td><td>物理内存占用百分比</td></tr><tr><td>↑ 网络上行</td><td>蓝色</td><td>所有网卡上传速率之和</td></tr><tr><td>↓ 网络下行</td><td>橙色</td><td>所有网卡下载速率之和</td></tr><tr><td>GPU0 / GPU1...</td><td>按使用率变色</td><td>每张显卡的使用率百分比</td></tr></tbody></table><p>右侧还有一个实时更新的时钟，方便你截图记录时参考时间戳。</p><h3 id="cpu-监控卡片" tabindex="-1">CPU 监控卡片 <a class="header-anchor" href="#cpu-监控卡片" aria-label="Permalink to &quot;CPU 监控卡片&quot;">​</a></h3><p>CPU 卡片是信息最丰富的区域，包含：</p><ul><li><strong>使用率折线图</strong>：过去 60 秒的全局 CPU 使用率变化曲线</li><li><strong>实时频率</strong>：当前 CPU 实际运行频率（Windows 下通过 PDH 计数器获取，含睿频信息）</li><li><strong>基准频率</strong>：CPU 的基础标称频率</li><li><strong>温度</strong>：CPU 当前温度（平台支持时显示，按温度变色：&lt;50° 正常、50-80° 橙色、&gt;80° 红色）</li><li><strong>进程数</strong>：当前正在运行的进程数量</li><li><strong>运行时间</strong>：系统已连续运行的总时长</li><li><strong>多核热力矩阵</strong>：每个逻辑核心以一个小色块表示，颜色越深代表该核心负载越高（蓝→橙→红渐变），一眼看出哪些核心在&quot;摸鱼&quot;、哪些在&quot;拼命&quot;</li></ul><blockquote><p>TODO: 截图 - CPU 卡片，标注折线图、多核热力矩阵和关键指标</p></blockquote><h3 id="内存监控卡片" tabindex="-1">内存监控卡片 <a class="header-anchor" href="#内存监控卡片" aria-label="Permalink to &quot;内存监控卡片&quot;">​</a></h3><ul><li><strong>使用率折线图</strong>：过去 60 秒的内存占用趋势</li><li><strong>物理内存（RAM）条形图</strong>：已用 / 总量，附带百分比</li><li><strong>Swap 条形图</strong>：如果系统启用了 Swap 且总量大于 0 会显示，使用橙色渐变条</li></ul><blockquote><p>TODO: 截图 - 内存卡片，标注 RAM 和 Swap 条形图</p></blockquote><h3 id="磁盘监控卡片" tabindex="-1">磁盘监控卡片 <a class="header-anchor" href="#磁盘监控卡片" aria-label="Permalink to &quot;磁盘监控卡片&quot;">​</a></h3><p>磁盘卡片采用列表形式展示所有挂载点，每个磁盘包含：</p><ul><li><strong>磁盘名称和挂载点</strong>：如 <code>C:</code>、<code>D:</code> 等</li><li><strong>容量条形图</strong>：已用 / 总量，百分比数字</li><li><strong>I/O 读写速率</strong>：当前读取速率（绿色）和写入速率（橙色）</li><li><strong>I/O 趋势迷你图</strong>：双系列折线图（绿色读取 + 橙色写入），展示 I/O 变化趋势</li></ul><blockquote><p>TODO: 截图 - 磁盘卡片，标注容量条形图和 I/O 趋势图</p></blockquote><h3 id="网络监控卡片" tabindex="-1">网络监控卡片 <a class="header-anchor" href="#网络监控卡片" aria-label="Permalink to &quot;网络监控卡片&quot;">​</a></h3><ul><li><strong>上/下行折线图</strong>：两条独立的折线图，上行蓝色、下行橙色</li><li><strong>总速率显示</strong>：卡片顶部的 <code>↑ ↓</code> 数值为所有网卡的总和</li><li><strong>接口详情列表</strong>：列出每个网卡独立的速率，列表最多显示 120px 高度，超过可滚动查看</li></ul><blockquote><p>TODO: 截图 - 网络卡片，标注上/下行折线图和接口列表</p></blockquote><h3 id="gpu-监控卡片" tabindex="-1">GPU 监控卡片 <a class="header-anchor" href="#gpu-监控卡片" aria-label="Permalink to &quot;GPU 监控卡片&quot;">​</a></h3><p>每张 NVIDIA 独立显卡会生成一张独立卡片，支持多卡环境（如双卡工作站）：</p><ul><li><strong>使用率折线图</strong>：过去 60 秒的 GPU 使用率</li><li><strong>温度</strong>：显卡当前温度，颜色随温度变化</li><li><strong>显存条形图</strong>：已用 / 总量，蓝色渐变条</li><li><strong>编码器使用率</strong>（NVIDIA 专属）：视频编码引擎的负载百分比</li><li><strong>解码器使用率</strong>（NVIDIA 专属）：视频解码引擎的负载百分比</li></ul><blockquote><p>TODO: 截图 - GPU 卡片，标注显存条形图和编解码使用率</p></blockquote><h3 id="工具栏操作" tabindex="-1">工具栏操作 <a class="header-anchor" href="#工具栏操作" aria-label="Permalink to &quot;工具栏操作&quot;">​</a></h3><p>页面右上角的工具栏提供了三种操作：</p><table tabindex="0"><thead><tr><th>操作</th><th>图标</th><th>说明</th></tr></thead><tbody><tr><td><strong>复制状态</strong></td><td>📋</td><td>将当前快照格式化为易读的文本报告，复制到剪贴板，方便粘贴到聊天工具或 Issue 中</td></tr><tr><td><strong>导出历史</strong></td><td>⬇️</td><td>弹出系统保存对话框，将最近 60 个采样点的完整快照导出为 JSON 文件</td></tr><tr><td><strong>切换密度</strong></td><td>▦</td><td>在紧凑（Small）/ 标准（Medium）/ 宽大（Large）三档之间切换，持久化到本地存储</td></tr></tbody></table><h3 id="三态视图" tabindex="-1">三态视图 <a class="header-anchor" href="#三态视图" aria-label="Permalink to &quot;三态视图&quot;">​</a></h3><p>工具会自动根据当前监控状态展示不同的界面：</p><table tabindex="0"><thead><tr><th>状态</th><th>展示内容</th></tr></thead><tbody><tr><td><strong>从未启动</strong></td><td>空状态提示 + 蓝色&quot;立即开启&quot;按钮</td></tr><tr><td><strong>启动中</strong></td><td>旋转加载图标 + &quot;正在采集系统数据…&quot;文字</td></tr><tr><td><strong>正常运行或暂停后</strong></td><td>完整的仪表盘（暂停后保留最后一帧数据，不会闪烁或消失）</td></tr></tbody></table><h3 id="主题适配" tabindex="-1">主题适配 <a class="header-anchor" href="#主题适配" aria-label="Permalink to &quot;主题适配&quot;">​</a></h3><p>所有监控卡片都遵循项目的主题外观系统，支持毛玻璃效果和透明度调整。你可以在设置中调整界面质感，监控卡片会自动适配。</p><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="监控暂停后分析数据" tabindex="-1">监控暂停后分析数据 <a class="header-anchor" href="#监控暂停后分析数据" aria-label="Permalink to &quot;监控暂停后分析数据&quot;">​</a></h3><p>点击右上角的开关暂停监控后，仪表盘会<strong>保留最后一帧数据</strong>，不会清空。你可以在这个&quot;冻结&quot;的状态下仔细分析各项指标，或者点击复制按钮将当前数据分享给他人。</p><h3 id="使用紧凑模式腾出屏幕空间" tabindex="-1">使用紧凑模式腾出屏幕空间 <a class="header-anchor" href="#使用紧凑模式腾出屏幕空间" aria-label="Permalink to &quot;使用紧凑模式腾出屏幕空间&quot;">​</a></h3><p>如果你需要一边监控一边做其他工作，或者屏幕尺寸较小，可以通过工具栏左侧的布局按钮切换到 <strong>紧凑（Small）</strong> 模式。紧凑模式下卡片间距更小、字体更紧凑、折线图更矮，能在有限空间内展示更多信息。</p><h3 id="导出-json-历史进行深度分析" tabindex="-1">导出 JSON 历史进行深度分析 <a class="header-anchor" href="#导出-json-历史进行深度分析" aria-label="Permalink to &quot;导出 JSON 历史进行深度分析&quot;">​</a></h3><p>工具保留最近 60 秒的完整快照历史。点击导出按钮，会弹出保存对话框让你选择存储位置。导出的 JSON 文件包含每个时间点的完整系统状态（CPU、内存、磁盘、网络、GPU），你可以用其他工具（如 Excel、Python）做进一步分析，比如：</p><ul><li>绘制长时间段的性能趋势图</li><li>分析特定进程（进程数指标）与 CPU 负载的关系</li><li>对比不同时间段的内存使用峰值</li></ul><h3 id="配合其他工具使用" tabindex="-1">配合其他工具使用 <a class="header-anchor" href="#配合其他工具使用" aria-label="Permalink to &quot;配合其他工具使用&quot;">​</a></h3><p>当你使用 <strong>视频转码工具</strong> 或 <strong>AI 对话</strong> 等计算密集型工具时，可以同时打开系统脉搏观察资源消耗情况——比如查看 GPU 使用率是否跑满、内存是否接近上限、CPU 温度是否过高。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-为什么我看不到-gpu-卡片" tabindex="-1">Q：为什么我看不到 GPU 卡片？ <a class="header-anchor" href="#q-为什么我看不到-gpu-卡片" aria-label="Permalink to &quot;Q：为什么我看不到 GPU 卡片？&quot;">​</a></h3><p>系统脉搏使用 NVIDIA Management Library（NVML）来获取 GPU 数据，因此<strong>仅支持 NVIDIA 显卡</strong>。如果你的电脑使用的是 AMD 或 Intel 集成显卡，GPU 区域将不会显示任何卡片。这是已知限制，不影响其他指标的监控。</p><h3 id="q-cpu-温度显示为-—-或空白" tabindex="-1">Q：CPU 温度显示为&quot;—&quot;或空白？ <a class="header-anchor" href="#q-cpu-温度显示为-—-或空白" aria-label="Permalink to &quot;Q：CPU 温度显示为&quot;—&quot;或空白？&quot;">​</a></h3><p>CPU 温度的读取依赖于 sysinfo 库的 <code>Components</code> 接口，该接口在部分 Windows 系统上无法正确读取温度传感器数据。这种情况下温度字段会返回 <code>null</code>，卡片上该条目不会显示。这不是硬件故障，只是数据不可获取。</p><h3 id="q-磁盘的-i-o-读写速率不准确" tabindex="-1">Q：磁盘的 I/O 读写速率不准确？ <a class="header-anchor" href="#q-磁盘的-i-o-读写速率不准确" aria-label="Permalink to &quot;Q：磁盘的 I/O 读写速率不准确？&quot;">​</a></h3><p>在 Windows 系统上，工具通过 PDH 计数器获取磁盘 I/O 速率，但 PDH 提供的是 <strong>全盘汇总值</strong>。目前实现将汇总值填入系统盘（如 <code>C:\\</code>），其余磁盘的 I/O 字段显示为 0。这意味着多磁盘环境下只有系统盘的 I/O 数据是准确的。这是当前版本的已知限制。</p><h3 id="q-暂停后数据会不会丢失" tabindex="-1">Q：暂停后数据会不会丢失？ <a class="header-anchor" href="#q-暂停后数据会不会丢失" aria-label="Permalink to &quot;Q：暂停后数据会不会丢失？&quot;">​</a></h3><p>不会。暂停监控时，系统会<strong>保留最后一帧快照</strong>和所有历史数据。你可以继续查看、复制或导出已采集的数据。只有关闭工具页面或刷新后数据才会被清除。</p><h3 id="q-历史趋势图能看更长时间的记录吗" tabindex="-1">Q：历史趋势图能看更长时间的记录吗？ <a class="header-anchor" href="#q-历史趋势图能看更长时间的记录吗" aria-label="Permalink to &quot;Q：历史趋势图能看更长时间的记录吗？&quot;">​</a></h3><p>目前每个维度的历史趋势图固定保留最近 <strong>60 个采样点</strong>（约 60 秒）。这是一个定长环形缓冲区（RingBuffer）设计，目的是平衡内存开销和可视化效果。如果你需要更长时间的记录，可以使用导出功能将完整快照保存为 JSON 文件，再用其他工具分析。</p>',69)])])}const q=o(l,[["render",n]]);export{c as __pageData,q as default};
